gable.create(tweakClass, { type: 'x,y', allowEventDefault: true, trigger: tweakClass + ' button.tp-rotv_b', }) document.querySelector(tweakClass).addEventListener('dblclick', () => { gsap.to(tweakClass, { x: `+=${d[0].x * -1}`, y: `+=${d[0].y * -1}`, onComplete: () => { gsap.set(tweakClass, { clearProps: 'all' }) }, }) }) update() // Add your prototype logic here... const updateMask = () => { const { left, top } = maskContainer.getBoundingClientRect() svgMask.setAttribute( 'viewBox', `0 0 ${maskContainer.offsetWidth} ${maskContainer.offsetHeight}`, ) const maskString = new Array(radios.length) .fill() .map((_, i) => { const { x, y, width, height } = labels[i].getBoundingClientRect() return `<rect x="${x - left}" y="${y - top}" width="${width}" height="${height}" rx="${height * 0.5}" ry="${height * 0.5}" fill="#000"></rect>` }) .join('') svgMask.innerHTML = maskString const encoded = encodeURIComponent(svgMask.outerHTML) .replace(/'/g, '%27') .replace(/"/g, '%22') const dataUri = `data:image/svg+xml;utf8,${encoded}` document.documentElement.style.setProperty('--svg-mask', `url(${dataUri})`) } const resizeHandler = new ResizeObserver(() => { if ( config.style === 'anchor' ) { updateMask() if (!CSS.supports('anchor-name: --active')) { cacheBase() syncChecked() } } }) resizeHandler.observe(resizeContainer) const positions = [] // syncs the positions of the labels const syncChecked = () => { const checked = fieldset.querySelector(':checked') const index = radios.indexOf(checked) fields.style.setProperty('--top', positions[index].top) fields.style.setProperty('--left', positions[index].left) fields.style.setProperty('--width', positions[index].width) fields.style.setProperty('--height', positions[index].height) fields.style.setProperty('--marker-top', positions[index].top) fields.style.setProperty('--marker-left', positions[index].left) } // this caches the positions of the labels const cacheBase = () => { console.info('cacheing') const { x: fieldX, y: fieldY } = fields.g